use std::io;

fn can_eat_row(r: &Vec<bool>) -> bool {
  for i in 0..r.len() {
    if !r[i] { return false }
  }
  true
}

fn can_eat_col(m: &Vec<Vec<bool>>, j: usize) -> bool {
  for r in m {
    if !r[j] { return false }
  }
  true
}

fn main() {
  let mut s = String::new();
  io::stdin().read_line(&mut s).unwrap();
  let a: Vec<i32> = s.split_whitespace()
    .map(|x| x.parse().unwrap())
    .collect();

  let r = a[0];
  let c = a[1];

  let mut v: Vec<Vec<bool>> = vec![];

  for _ in 0..r {
    let mut s = String::new();
    io::stdin().read_line(&mut s).unwrap();
    v.push(s.trim().chars()
      .map(|x| x == '.')
      .collect()
    );
  }

  let mut eatable_rows = vec![];
  for i in 0..r as usize {
    if can_eat_row(&v[i]) { eatable_rows.push(i); }
  }

  let mut eatable_cols = vec![];
  for j in 0..c as usize {
    if can_eat_col(&v, j) { eatable_cols.push(j); }
  }

  let er = eatable_rows.len() as i32;
  let ec = eatable_cols.len() as i32;

  if er == 0 {
    println!("{}", ec*r);
  } else if ec == 0 {
    println!("{}", er*c);
  } else {
    println!("{}", er*c + ec*(r-er));
  }
}
